    48→/**
    49→ * During moving {@link kafka.server.KafkaConfig} out of core AbstractKafkaConfig will be the future KafkaConfig
    50→ * so any new getters, or updates to `CONFIG_DEF` will be defined here.
    51→ * Any code depends on kafka.server.KafkaConfig will keep for using kafka.server.KafkaConfig for the time being until we move it out of core
    52→ * For more details check KAFKA-15853
    53→ */
    54→public abstract class AbstractKafkaConfig extends AbstractConfig {
    55→    public static final ConfigDef CONFIG_DEF = Utils.mergeConfigs(List.of(
    56→        RemoteLogManagerConfig.configDef(),
    57→        ServerConfigs.CONFIG_DEF,
    58→        KRaftConfigs.CONFIG_DEF,
    59→        MetadataLogConfig.CONFIG_DEF,
    60→        SocketServerConfigs.CONFIG_DEF,
    61→        ReplicationConfigs.CONFIG_DEF,
    62→        GroupCoordinatorConfig.CONFIG_DEF,
    63→        CleanerConfig.CONFIG_DEF,
    64→        LogConfig.SERVER_CONFIG_DEF,
    65→        ShareGroupConfig.CONFIG_DEF,
    66→        ShareCoordinatorConfig.CONFIG_DEF,
    67→        TransactionLogConfig.CONFIG_DEF,
    68→        TransactionStateManagerConfig.CONFIG_DEF,
    69→        QuorumConfig.CONFIG_DEF,
    70→        MetricConfigs.CONFIG_DEF,
    71→        QuotaConfig.CONFIG_DEF,
    72→        BrokerSecurityConfigs.CONFIG_DEF,
    73→        DelegationTokenManagerConfigs.CONFIG_DEF,
    74→        AddPartitionsToTxnConfig.CONFIG_DEF
    75→    ));
