    77→    public AbstractKafkaConfig(ConfigDef definition, Map<?, ?> originals, Map<String, ?> configProviderProps, boolean doLog) {
    78→        super(definition, originals, configProviderProps, doLog);
    79→    }
    80→
    81→    public List<String> logDirs() {
    82→        return Csv.parseCsvList(Optional.ofNullable(getString(ServerLogConfigs.LOG_DIRS_CONFIG)).orElse(getString(ServerLogConfigs.LOG_DIR_CONFIG)));
    83→    }
