    97→    public int backgroundThreads() {
    98→        return getInt(ServerConfigs.BACKGROUND_THREADS_CONFIG);
    99→    }
   100→
   101→    public int brokerId() {
   102→        return getInt(ServerConfigs.BROKER_ID_CONFIG);
   103→    }
   104→
   105→    public int requestTimeoutMs() {
   106→        return getInt(ServerConfigs.REQUEST_TIMEOUT_MS_CONFIG);
   107→    }
   108→
   109→    public List<String> controllerListenerNames() {
   110→        return Csv.parseCsvList(getString(KRaftConfigs.CONTROLLER_LISTENER_NAMES_CONFIG));
   111→    }
   112→
   113→    public ListenerName interBrokerListenerName() {
   114→        return interBrokerListenerNameAndSecurityProtocol().getKey();
   115→    }
   116→
   117→    public SecurityProtocol interBrokerSecurityProtocol() {
   118→        return interBrokerListenerNameAndSecurityProtocol().getValue();
   119→    }
