   121→    public Map<ListenerName, SecurityProtocol> effectiveListenerSecurityProtocolMap() {
   122→        Map<ListenerName, SecurityProtocol> mapValue =
   123→                getMap(SocketServerConfigs.LISTENER_SECURITY_PROTOCOL_MAP_CONFIG,
   124→                        getString(SocketServerConfigs.LISTENER_SECURITY_PROTOCOL_MAP_CONFIG))
   125→                        .entrySet()
   126→                        .stream()
   127→                        .collect(Collectors.toMap(
   128→                                e -> ListenerName.normalised(e.getKey()),
   129→                                e -> securityProtocol(
   130→                                        e.getValue(),
   131→                                        SocketServerConfigs.LISTENER_SECURITY_PROTOCOL_MAP_CONFIG)));
   132→
   133→        if (!originals().containsKey(SocketServerConfigs.LISTENER_SECURITY_PROTOCOL_MAP_CONFIG)) {
   134→            // Using the default configuration since listener.security.protocol.map is not explicitly set.
   135→            // Before adding default PLAINTEXT mappings for controller listeners, verify that:
   136→            // 1. No SSL or SASL protocols are used in controller listeners
   137→            // 2. No SSL or SASL protocols are used in regular listeners (Note: controller listeners
   138→            //    are not included in 'listeners' config when process.roles=broker)
   139→            if (controllerListenerNames().stream().anyMatch(AbstractKafkaConfig::isSslOrSasl) ||
   140→                    Csv.parseCsvList(getString(SocketServerConfigs.LISTENERS_CONFIG)).stream()
   141→                            .anyMatch(listenerName -> isSslOrSasl(parseListenerName(listenerName)))) {
   142→                return mapValue;
   143→            } else {
   144→                // Add the PLAINTEXT mappings for all controller listener names that are not explicitly PLAINTEXT
   145→                mapValue.putAll(controllerListenerNames().stream()
   146→                        .filter(listenerName -> !SecurityProtocol.PLAINTEXT.name.equals(listenerName))
   147→                        .collect(Collectors.toMap(ListenerName::new, ignored -> SecurityProtocol.PLAINTEXT)));
   148→                return mapValue;
   149→            }
   150→        } else {
   151→            return mapValue;
   152→        }
   153→    }
   154→
   155→    public static Map<String, String> getMap(String propName, String propValue) {
   156→        try {
   157→            return Csv.parseCsvMap(propValue);
   158→        } catch (Exception e) {
   159→            throw new IllegalArgumentException(
   160→                    String.format("Error parsing configuration property '%s': %s", propName, e.getMessage()));
   161→        }
   162→    }
   163→
   164→    private static SecurityProtocol securityProtocol(String protocolName, String configName) {
   165→        try {
   166→            return SecurityProtocol.forName(protocolName);
   167→        } catch (IllegalArgumentException e) {
   168→            throw new ConfigException(
   169→                    String.format("Invalid security protocol `%s` defined in %s", protocolName, configName));
   170→        }
   171→    }
   172→
   173→    private Map.Entry<ListenerName, SecurityProtocol> interBrokerListenerNameAndSecurityProtocol() {
   174→        String interBrokerListenerName = getString(ReplicationConfigs.INTER_BROKER_LISTENER_NAME_CONFIG);
   175→        if (interBrokerListenerName != null) {
   176→            if (originals().containsKey(ReplicationConfigs.INTER_BROKER_SECURITY_PROTOCOL_CONFIG)) {
   177→                throw new ConfigException(String.format("Only one of %s and %s should be set.",
   178→                        ReplicationConfigs.INTER_BROKER_LISTENER_NAME_CONFIG,
   179→                        ReplicationConfigs.INTER_BROKER_SECURITY_PROTOCOL_CONFIG));
   180→            }
   181→            ListenerName listenerName = ListenerName.normalised(interBrokerListenerName);
   182→            SecurityProtocol securityProtocol = effectiveListenerSecurityProtocolMap().get(listenerName);
   183→            if (securityProtocol == null) {
   184→                throw new ConfigException("Listener with name " + listenerName.value() + " defined in " +
   185→                        ReplicationConfigs.INTER_BROKER_LISTENER_NAME_CONFIG + " not found in " +
   186→                        SocketServerConfigs.LISTENER_SECURITY_PROTOCOL_MAP_CONFIG + ".");
   187→            }
   188→            return Map.entry(listenerName, securityProtocol);
   189→        } else {
   190→            SecurityProtocol securityProtocol = securityProtocol(
   191→                    getString(ReplicationConfigs.INTER_BROKER_SECURITY_PROTOCOL_CONFIG),
   192→                    ReplicationConfigs.INTER_BROKER_SECURITY_PROTOCOL_CONFIG);
   193→            return Map.entry(ListenerName.forSecurityProtocol(securityProtocol), securityProtocol);
   194→        }
   195→    }
   196→
   197→    private static boolean isSslOrSasl(String name) {
   198→        return name.equals(SecurityProtocol.SSL.name) || name.equals(SecurityProtocol.SASL_SSL.name) ||
   199→                name.equals(SecurityProtocol.SASL_PLAINTEXT.name);
   200→    }

